242	  const applicationDetailsPath =
243	    applicationDetails
244	      .replace(':namespace', app.namespace)
245	      .replace(':name', app.name) +
246	    '?apiVersion=' +
247	    apiVersion;
248	  return !!app.namespace ? (
249	    <div>
250	      <Text className="mco-cluster-app__headerText--size mco-dashboard__statusText--margin">
