252	        {appType === DRApplication.DISCOVERED ? (
253	          app.name
254	        ) : (
255	          <Link id="app-search-argo-apps-link" to={applicationDetailsPath}>
256	            {app.name}
257	          </Link>
258	        )}
259	      </Text>
260	      <Text className="mco-dashboard__statusText--margin">
261	        {t('Type: {{type}}', {
262	          type: APPLICATION_TYPE_DISPLAY_TEXT(t)[appType],
