271	export const ClusterAppCard: React.FC = () => {
272	  const [cluster, setCluster] = React.useState<string>();
273	  const [application, setApplication] = React.useState<ApplicationObj>({
274	    namespace: undefined,
275	    name: ALL_APPS,
276	  });
277	  const [mcvs, mcvsLoaded, mcvsLoadError] = useK8sWatchResource<
278	    ACMManagedClusterViewKind[]
279	  >({
280	    kind: referenceForModel(ACMManagedClusterViewModel),
281	    isList: true,
282	    namespace: cluster,
283	    namespaced: true,
284	    optional: true,
285	  });
286	  const [lastSyncTimeData, lastSyncTimeError, lastSyncTimeLoading] =
287	    useCustomPrometheusPoll({
288	      endpoint: 'api/v1/query' as any,
289	      query: !!cluster ? getLastSyncPerClusterQuery() : null,
290	      basePath: usePrometheusBasePath(),
291	    });
292	
293	  const {
294	    csvStatus: { data: csvData, error: csvError, loading: csvLoading },
295	    podStatus: { data: podData, error: podError, loading: podLoading },
296	  } = React.useContext(OperatorStatusesContext);
297	
298	  const { drClusterAppsMap, loaded, loadError } =
299	    React.useContext(DRResourcesContext);
300	
301	  const allLoaded =
302	    loaded && !csvLoading && !lastSyncTimeLoading && mcvsLoaded && !podLoading;
303	  const anyError =
304	    lastSyncTimeError || csvError || loadError || mcvsLoadError || podError;
305	
306	  const selectedApplication: ProtectedAppsMap = React.useMemo(() => {
307	    const { name, namespace } = application || {};
308	    return !!namespace && name !== ALL_APPS
309	      ? drClusterAppsMap[cluster]?.protectedApps?.find(
310	          (protectedApp) =>
311	            protectedApp?.appName === name &&
312	            protectedApp?.appNamespace === namespace
313	        )
314	      : undefined;
315	  }, [application, drClusterAppsMap, cluster]);
316	
317	  const protectedPVCData: ProtectedPVCData[] = React.useMemo(() => {
318	    const pvcsData =
319	      (mcvsLoaded && !mcvsLoadError && getProtectedPVCFromVRG(mcvs)) || [];
320	    const protectedApps = !!selectedApplication
321	      ? [selectedApplication]
322	      : drClusterAppsMap[cluster]?.protectedApps;
323	    return filterPVCDataUsingApps(pvcsData, protectedApps);
324	  }, [
325	    drClusterAppsMap,
326	    selectedApplication,
327	    cluster,
328	    mcvs,
329	    mcvsLoaded,
330	    mcvsLoadError,
331	  ]);
332	
333	  const loadedWOError = allLoaded && !anyError;
334	  return (
335	    <Card data-test="cluster-app-card">
336	      {loadedWOError && (
337	        <CardHeader className="mco-cluster-app__text--divider">
338	          <div className="mco-dashboard__contentColumn">
339	            <ClusterAppDropdown
340	              clusterResources={drClusterAppsMap}
341	              clusterName={cluster}
342	              application={application}
343	              setCluster={setCluster}
344	              setApplication={setApplication}
345	            />
346	            <CardTitle className="mco-cluster-app__text--margin-top">
347	              <ClusterAppCardTitle
348	                app={application}
349	                cluster={cluster}
350	                appKind={selectedApplication?.appKind}
351	                appType={selectedApplication?.appType}
352	                appAPIVersion={selectedApplication?.appAPIVersion}
353	              />
354	            </CardTitle>
355	          </div>
356	        </CardHeader>
357	      )}
358	      <CardBody>
359	        {loadedWOError &&
360	          (!application.namespace && application.name === ALL_APPS ? (
361	            <ClusterWiseCard
362	              clusterName={cluster}
363	              lastSyncTimeData={lastSyncTimeData}
364	              protectedPVCData={protectedPVCData}
365	              csvData={csvData}
366	              podData={podData}
367	              clusterResources={drClusterAppsMap}
368	            />
369	          ) : (
370	            <AppWiseCard
371	              protectedPVCData={protectedPVCData}
372	              selectedApplication={selectedApplication}
373	            />
374	          ))}
375	        {!allLoaded && !anyError && (
376	          <div style={{ height: '200px' }}>
377	            <Skeleton height="100%" />
378	          </div>
379	        )}
380	        {anyError && (
381	          <div className="mco-dashboard__centerComponent">
382	            <DataUnavailableError />
383	          </div>
384	        )}
385	      </CardBody>
386	    </Card>
387	  );
388	};
389	
390	type ClusterWiseCardProps = {
391	  clusterName: string;
392	  lastSyncTimeData: PrometheusResponse;
393	  protectedPVCData: ProtectedPVCData[];
394	  csvData: PrometheusResponse;
395	  podData: PrometheusResponse;
396	  clusterResources: DRClusterAppsMap;
397	};
398	
399	type AppWiseCardProps = {
400	  protectedPVCData: ProtectedPVCData[];
401	  selectedApplication: ProtectedAppsMap;
402	};
403	
404	type ClusterAppCardTitleProps = {
405	  app: ApplicationObj;
406	  cluster: string;
407	  appKind: string;
408	  appAPIVersion: string;
409	  appType: DRApplication;
410	};

